def turned_on_materialised_views():
    return (
        hasattr(settings, "OSCAR_CATALOGUE_USE_POSTGRES_MATERIALISED_VIEWS")
        and settings.OSCAR_CATALOGUE_USE_POSTGRES_MATERIALISED_VIEWS
    )


def is_postgres():
    return connection.vendor == "postgresql"


@register()
def startup_check(*args, **kwargs):
    errors = []

    if (
        hasattr(settings, "OSCAR_PRODUCT_SEARCH_HANDLER")
        and settings.OSCAR_PRODUCT_SEARCH_HANDLER is not None
    ):
        errors.append(
            Error(
                "The OSCAR_PRODUCT_SEARCH_HANDLER is removed since django-oscar==3.2.4.",
                hint="Use the new class based haystack views instead located in search.views. Any customizations that has been done to the search handler should be moved there.",
                id="django-oscar.E001",
            )
        )

    if turned_on_materialised_views() and not is_postgres():
        errors.append(
            Warning(
                "OSCAR_CATALOGUE_USE_POSTGRES_MATERIALISED_VIEWS is enabled but PostgreSQL is not detected. Materialized views are not functioning and fallback queries are being used instead.",
                hint="Either switch your database backend to PostgreSQL or disable the OSCAR_CATALOGUE_USE_POSTGRES_MATERIALISED_VIEWS setting in your configuration.",
                id="django-oscar.W001",
            )
        )
    return errors


def use_productcategory_materialised_view():
    return is_postgres() and turned_on_materialised_views()

from django.contrib import messages


class FlashMessages(object):
    """
    Intermediate container for flash messages.

    This is useful as, at the time of creating the message, we don't know
    whether the response is an AJAX response or not.
    """

    def __init__(self):
        self.msgs = {}

    def add_message(self, level, message):
        self.msgs.setdefault(level, []).append(message)

    def add_messages(self, level, message_list):
        for msg in message_list:
            self.add_message(level, msg)

    def info(self, message):
        self.add_message(messages.INFO, message)

    def warning(self, message):
        self.add_message(messages.WARNING, message)

    def error(self, message):
        self.add_message(messages.ERROR, message)

    def success(self, message):
        self.add_message(messages.SUCCESS, message)

    def as_dict(self):
        payload = {}
        for level, msgs in self.msgs.items():
            tag = messages.DEFAULT_TAGS.get(level, "info")
            payload[tag] = [str(msg) for msg in msgs]
        return payload

    def apply_to_request(self, request):
        for level, msgs in self.msgs.items():
            for msg in msgs:
                messages.add_message(request, level, msg)

import warnings

from oscar.utils.deprecation import RemovedInOscar32Warning


def deprecated(obj):
    if isinstance(obj, type):
        return _deprecated_cls(cls=obj)
    else:
        return _deprecated_func(f=obj)


def _deprecated_func(f, warn_cls=RemovedInOscar32Warning):
    def _deprecated(*args, **kwargs):
        message = (
            "Method '%s' is deprecated and will be "
            "removed in the next version of django-oscar" % f.__name__
        )
        warnings.warn(message, warn_cls, stacklevel=2)
        return f(*args, **kwargs)

    return _deprecated


def _deprecated_cls(cls, warn_cls=RemovedInOscar32Warning):
    class Deprecated(cls):
        def __init__(self, *args, **kwargs):
            message = (
                "Class '%s' is deprecated and will be "
                "removed in the next version of django-oscar" % cls.__name__
            )
            warnings.warn(message, warn_cls, stacklevel=2)
            super().__init__(*args, **kwargs)

    return Deprecated

