class TestOrderSearchForm(TestCase):
    @override_settings(TIME_ZONE="Africa/Nairobi")
    def test_get_filters(self):
        form = OrderSearchForm(
            data={
                "date_from": date(2021, 1, 1),
                "date_to": date(2021, 1, 10),
                "order_number": "100",
            }
        )
        self.assertTrue(form.is_valid())

        filters = form.get_filters()
        nbi = pytz.timezone(settings.TIME_ZONE)
        self.assertEqual(
            filters,
            {
                "date_placed__gte": nbi.localize(datetime(2021, 1, 1)),
                "date_placed__lte": nbi.localize(
                    datetime(2021, 1, 10, 23, 59, 59, 999999)
                ),
                "number__contains": "100",
            },
        )

    def test_orders_descriptions(self):
        form = OrderSearchForm(
            data={
                "date_from": "2023-01-01",
                "date_to": "2023-01-02",
                "order_number": "100",
            }
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders placed between 2023-01-01 and 2023-01-02 and order number containing 100",
        )

        form = OrderSearchForm(
            data={
                "date_from": "2023-01-01",
                "date_to": "2023-01-02",
                "order_number": "",
            }
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders placed between 2023-01-01 and 2023-01-02",
        )

        form = OrderSearchForm(
            data={"date_from": "2023-01-01", "date_to": "", "order_number": "100"}
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders placed since 2023-01-01 and order number containing 100",
        )

        form = OrderSearchForm(
            data={"date_from": "2023-01-01", "date_to": "", "order_number": ""}
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders placed since 2023-01-01",
        )

        form = OrderSearchForm(
            data={"date_from": "", "date_to": "2023-01-02", "order_number": "100"}
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders placed until 2023-01-02 and order number containing 100",
        )

        form = OrderSearchForm(
            data={"date_from": "", "date_to": "2023-01-02", "order_number": ""}
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders placed until 2023-01-02",
        )

        form = OrderSearchForm(
            data={"date_from": "", "date_to": "", "order_number": "100"}
        )
        self.assertTrue(form.is_valid())
        self.assertEqual(
            form.description(),
            "Orders with order number containing 100",
        )

        form = OrderSearchForm(
            data={"date_from": "", "date_to": "", "order_number": ""}
        )
        # at least one field is required!
        self.assertFalse(form.is_valid())
        # if form is not valid, description = "All orders"
        self.assertEqual(form.description(), "All orders")

